INSERT INTO "ecos_knowledge_document" ("id", "title", "content", "doc_type", "tags", "entity_types", "embedding") VALUES ('doc_supplier_exit', '供应商退出管理规程', '一、退出情形：年度评级为D级的；发生重大质量事故造成严重后果的；连续两年评级为C级且未完成整改的；经营状况严重恶化丧失履约能力的；存在严重违法违规行为的。
二、退出流程：采购部门提出退出建议附证明材料；质量部门法务部门联合审核；报总经理审批；向供应商发出书面退出通知；处理未完结订单和质保事宜。
